//========================================================================================================================================================================================================200
//	DEFINE/INCLUDE
//========================================================================================================================================================================================================200

#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu_2.h"

//========================================================================================================================================================================================================200
//	KERNEL_CPU_2 FUNCTION
//========================================================================================================================================================================================================200

void 
kernel_cpu_2(	int cores_arg,

				knode *knodes,
				long knodes_elem,

				int order,
				long maxheight,
				int count,

				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	//======================================================================================================================================================150
	//	Variables
	//======================================================================================================================================================150

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;

	time0 = get_time();

	// threads per block equivalent
	int threadsPerBlock;
	threadsPerBlock = order < 1024 ? order : 1024;

	// blocks per grid equivalent
	int blocksPerGrid;
	blocksPerGrid = count;

	printf("# of blocks = %d, # of threads/block = %d\n", blocksPerGrid, threadsPerBlock);

	time1 = get_time();

	//======================================================================================================================================================150
	//	KERNEL (OpenMP parallel over blocks/queries)
	//======================================================================================================================================================150

	time2 = get_time();

	#pragma omp parallel for num_threads(cores_arg) schedule(static)
	for (int bid = 0; bid < count; bid++) {

		// process levels of the tree
		for (int i = 0; i < maxheight; i++) {

			for (int thid = 0; thid < threadsPerBlock; thid++) {
				if ((knodes[currKnode[bid]].keys[thid] <= start[bid]) &&
				    (knodes[currKnode[bid]].keys[thid+1] > start[bid])) {
					if (knodes[currKnode[bid]].indices[thid] < knodes_elem) {
						offset[bid] = knodes[currKnode[bid]].indices[thid];
					}
				}
				if ((knodes[lastKnode[bid]].keys[thid] <= end[bid]) &&
				    (knodes[lastKnode[bid]].keys[thid+1] > end[bid])) {
					if (knodes[lastKnode[bid]].indices[thid] < knodes_elem) {
						offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
					}
				}
			}

			// set for next tree level (thid == 0 action)
			currKnode[bid] = offset[bid];
			lastKnode[bid] = offset_2[bid];
		}

		// process leaves
		// Find the index of the starting record
		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
				recstart[bid] = knodes[currKnode[bid]].indices[thid];
			}
		}

		// Find the index of the ending record
		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
				reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
			}
		}
	}

	time3 = get_time();

	//======================================================================================================================================================150
	//	DISPLAY TIMING
	//======================================================================================================================================================150

	time4 = get_time();
	time5 = get_time();

	printf("Time spent in different stages of CPU KERNEL:\n");

	printf("%15.12f s, %15.12f %% : CPU: SETUP\n",
		(float)(time1-time0) / 1000000, (float)(time1-time0) / (float)(time5-time0) * 100);
	printf("%15.12f s, %15.12f %% : CPU: KERNEL PARAMS\n",
		(float)(time2-time1) / 1000000, (float)(time2-time1) / (float)(time5-time0) * 100);
	printf("%15.12f s, %15.12f %% : CPU: KERNEL\n",
		(float)(time3-time2) / 1000000, (float)(time3-time2) / (float)(time5-time0) * 100);
	printf("%15.12f s, %15.12f %% : CPU: CLEANUP\n",
		(float)(time4-time3) / 1000000, (float)(time4-time3) / (float)(time5-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time5-time0) / 1000000);
}
